     1→use regex::Regex;
     2→use serde_json::Value;
     3→use std::fs;
     4→
     5→use super::patterns::*;
     6→
     7→/// Extract text content from message.content (string or array of text blocks).
     8→pub fn extract_text(content: &Option<Value>) -> String {
     9→    match content {
    10→        None => String::new(),
    11→        Some(Value::String(s)) => s.clone(),
    12→        Some(Value::Array(blocks)) => {
    13→            let mut parts = Vec::new();
    14→            for block in blocks {
    15→                if let Some(block_type) = block.get("type").and_then(|v| v.as_str()) {
    16→                    if block_type == "text" {
    17→                        if let Some(text) = block.get("text").and_then(|v| v.as_str()) {
    18→                            if !text.is_empty() {
    19→                                parts.push(text.to_string());
    20→                            }
    21→                        }
    22→                    }
    23→                }
    24→            }
    25→            parts.join("\n")
    26→        }
    27→        _ => String::new(),
    28→    }
    29→}
    30→
    31→/// SanitizeContent removes noise XML tags and converts command tags into
    32→/// a human-readable slash command format for display.
    33→pub fn sanitize_content(s: &str) -> String {
    34→    // Command output messages: extract the inner content.
    35→    if is_command_output(s) {
    36→        let out = extract_command_output(s);
    37→        if !out.is_empty() {
    38→            return out;
    39→        }
    40→    }
    41→
    42→    // Command messages: convert to "/name args" form.
    43→    if s.starts_with("<command-name>") || s.starts_with("<command-message>") {
    44→        if let Some(display) = extract_command_display(s) {
    45→            if !display.is_empty() {
    46→                return display;
    47→            }
    48→        }
    49→    }
    50→
    51→    // Strip noise tags.
    52→    let mut result = s.to_string();
    53→    for pat in NOISE_TAG_PATTERNS.iter() {
    54→        result = pat.replace_all(&result, "").to_string();
    55→    }
    56→
    57→    // Strip remaining command tags.
    58→    for pat in COMMAND_TAG_PATTERNS.iter() {
    59→        result = pat.replace_all(&result, "").to_string();
    60→    }
    61→
    62→    // Strip bash-input tags but keep inner content (the command text).
    63→    result = RE_BASH_INPUT.replace_all(&result, "$1").to_string();
    64→
    65→    result.trim().to_string()
    66→}
    67→
    68→/// Converts <command-name>/foo</command-name><command-args>bar</command-args>
    69→/// into "/foo bar".
    70→fn extract_command_display(s: &str) -> Option<String> {
    71→    let m = RE_COMMAND_NAME.captures(s)?;
    72→    let name = format!("/{}", m.get(1)?.as_str().trim());
    73→
    74→    if let Some(am) = RE_COMMAND_ARGS.captures(s) {
    75→        let args = am.get(1).map(|m| m.as_str().trim()).unwrap_or("");
    76→        if !args.is_empty() {
    77→            return Some(format!("{name} {args}"));
    78→        }
    79→    }
    80→    Some(name)
    81→}
    82→
    83→/// Returns true when content starts with a local-command output tag.
    84→/// (Only local-command tags, not bash/task tags.)
    85→pub fn is_command_output(s: &str) -> bool {
    86→    s.starts_with(LOCAL_COMMAND_STDOUT_TAG) || s.starts_with(LOCAL_COMMAND_STDERR_TAG)
    87→}
    88→
    89→/// Returns the inner text from <local-command-stdout> or <local-command-stderr>.
    90→/// Returns empty string if neither tag is found.
    91→pub fn extract_command_output(s: &str) -> String {
    92→    if let Some(caps) = RE_STDOUT.captures(s) {
    93→        if let Some(m) = caps.get(1) {
    94→            return m.as_str().trim().to_string();
    95→        }
    96→    }
    97→    if let Some(caps) = RE_STDERR.captures(s) {
    98→        if let Some(m) = caps.get(1) {
    99→            return m.as_str().trim().to_string();
   100→        }
   101→    }
   102→    String::new()
   103→}
   104→
   105→/// Returns the inner text from <bash-stdout> or <bash-stderr> wrapper tags.
   106→/// Tries stdout first, falls back to stderr.
   107→pub fn extract_bash_output(s: &str) -> String {
   108→    if let Some(caps) = RE_BASH_STDOUT.captures(s) {
   109→        if let Some(m) = caps.get(1) {
   110→            return m.as_str().trim().to_string();
   111→        }
   112→    }
   113→    if let Some(caps) = RE_BASH_STDERR.captures(s) {
   114→        if let Some(m) = caps.get(1) {
   115→            return m.as_str().trim().to_string();
   116→        }
   117→    }
   118→    String::new()
   119→}
   120→
   121→/// Pulls the human-readable summary from a <task-notification> XML wrapper.
   122→pub fn extract_task_notification(s: &str) -> String {
   123→    if let Some(caps) = RE_TASK_NOTIFY_SUMMARY.captures(s) {
   124→        if let Some(m) = caps.get(1) {
   125→            return m.as_str().trim().to_string();
   126→        }
   127→    }
   128→    // Fallback: strip all XML-like tags and return what's left.
   129→    let re_tags = Regex::new(r"<[^>]+>").unwrap();
   130→    let stripped = re_tags.replace_all(s, " ");
   131→    let re_spaces = Regex::new(r"\s+").unwrap();
   132→    re_spaces
   133→        .replace_all(stripped.trim(), " ")
   134→        .trim()
   135→        .to_string()
   136→}
   137→
   138→/// Converts tool_result content (string or array of text blocks) to a string.
   139→pub fn stringify_content(raw: &Option<Value>) -> String {
   140→    let val = match raw {
   141→        Some(v) => v,
   142→        None => return String::new(),
   143→    };
   144→
   145→    // Try string first.
   146→    if let Value::String(s) = val {
   147→        return s.clone();
   148→    }
   149→
   150→    // Try array of text blocks.
   151→    if let Value::Array(blocks) = val {
   152→        let parts: Vec<&str> = blocks
   153→            .iter()
   154→            .filter_map(|b| {
   155→                let text = b.get("text")?.as_str()?;
   156→                if !text.is_empty() {
   157→                    Some(text)
   158→                } else {
   159→                    None
   160→                }
   161→            })
   162→            .collect();
   163→        if !parts.is_empty() {
   164→            return parts.join("\n");
   165→        }
   166→    }
   167→
   168→    // Last resort: raw JSON string.
   169→    val.to_string()
   170→}
   171→
   172→/// Detects `<persisted-output>` markers in tool result content and resolves
   173→/// the file reference by reading the persisted file from disk.
   174→/// Returns the full file content if found, otherwise the original string.
   175→pub fn resolve_persisted_output(s: &str) -> String {
   176→    if !s.contains("<persisted-output>") {
   177→        return s.to_string();
   178→    }
   179→    if let Some(caps) = RE_PERSISTED_OUTPUT_PATH.captures(s) {
   180→        if let Some(m) = caps.get(1) {
   181→            let path = m.as_str().trim();
   182→            if let Ok(content) = fs::read_to_string(path) {
   183→                return content;
   184→            }
   185→        }
   186→    }
   187→    // File not found or no path match — return original content as fallback.
   188→    s.to_string()
   189→}
