              style={item.depth > 0 ? { paddingLeft: 12 + item.depth * 16 } : undefined}
              onClick={item.isGroup ? undefined : () => onSelectProject(item.key)}
            >
              <span
                className="project-tree__name"
                title={item.isGroup ? undefined : (item.key ?? undefined)}
