     9→const __dirname = dirname(fileURLToPath(import.meta.url));
    10→const root = resolve(__dirname, "..");
    11→
    12→const args = process.argv.slice(2);
    13→const mode = args.find((a) => ["--app", "--web", "--tui"].includes(a)) ?? "--app";
    14→const noOpen = args.includes("--no-open");
    15→
    16→function run(cmd, cmdArgs, opts = {}) {
    17→  const child = spawn(cmd, cmdArgs, {
    18→    stdio: "inherit",
    19→    cwd: root,
    20→    ...opts,
    21→  });
    22→  child.on("exit", (code) => process.exit(code ?? 0));
    23→  return child;
    24→}
    25→
    26→function ask(question) {
    27→  const rl = createInterface({ input: process.stdin, output: process.stdout });
    28→  return new Promise((res) => {
    29→    rl.question(question, (answer) => {
    30→      rl.close();
    31→      res(answer.trim().toLowerCase());
    32→    });
    33→  });
    34→}
    35→
    36→/** Check if a port is already in use. */
    37→function isPortInUse(port) {
    38→  return new Promise((res) => {
    39→    const sock = createConnection({ port, host: "127.0.0.1" });
    40→    sock.once("connect", () => {
    41→      sock.destroy();
    42→      res(true);
    43→    });
    44→    sock.once("error", () => res(false));
    45→  });
    46→}
    47→
    48→/** Open a URL in the default browser. */
    49→function openBrowser(url) {
    50→  try {
    51→    const os = platform();
    52→    if (os === "darwin") execSync(`open "${url}"`);
    53→    else if (os === "win32") execSync(`cmd.exe /c start "" "${url}"`);
    54→    else execSync(`xdg-open "${url}" 2>/dev/null`);
    55→  } catch {}
    56→}
    57→
    58→switch (mode) {
    59→  case "--app":
    60→    run("npx", ["tauri", "dev"]);
    61→    break;
    62→
    63→  case "--web": {
    64→    // Check if the server is already running on port 1420.
    65→    const alreadyRunning = await isPortInUse(1420);
    66→
    67→    if (noOpen) {
    68→      if (alreadyRunning) {
    69→        // Another instance owns the port — exit cleanly so launchd
    70→        // doesn't keep respawning us in a crash loop.
    71→        console.error("Port 1420 already in use, exiting.");
    72→        process.exit(0);
    73→      }
    74→      run("npx", ["tauri", "dev", "--", "--", "--web", "--no-open"]);
    75→    } else {
    76→      if (alreadyRunning) {
    77→        console.log("cctrace web server is already running on http://localhost:1420");
    78→        openBrowser("http://localhost:1420");
    79→        process.exit(0);
    80→      }
    81→
    82→      if (process.stdin.isTTY) {
    83→        // Interactive — ask how to start.
    84→        console.log("How would you like to start the web server?\n");
    85→        console.log("  1) Start now (foreground, stops when you close the terminal)");
    86→        console.log("  2) Install as background service (starts on login, always running)\n");
    87→
    88→        const answer = await ask("Choose [1/2]: ");
    89→
    90→        if (answer === "2") {
    91→          const { installService } = await import("./install-service.mjs");
    92→          installService();
    93→          // Poll until the server is actually ready, then open browser.
    94→          execSync("node wait-for-backend.mjs", {
    95→            stdio: "inherit",
    96→            cwd: resolve(root, "bin"),
    97→          });
    98→          openBrowser("http://localhost:1420");
    99→        } else {
   100→          run("npx", ["tauri", "dev", "--", "--", "--web"]);
   101→        }
   102→      } else {
   103→        // Non-interactive — just start.
   104→        run("npx", ["tauri", "dev", "--", "--", "--web"]);
   105→      }
   106→    }
   107→    break;
   108→  }
   109→
   110→  case "--tui": {
   111→    // Start backend headless, then launch TUI once API is ready
   112→    const backend = spawn("npx", ["tauri", "dev", "--", "--", "--headless"], {
   113→      stdio: "inherit",
   114→      cwd: root,
   115→    });
   116→
   117→    // Build TUI if needed, wait for backend, then start TUI
